167	/// Convert `mir.sub` to `llvm.sub` (integer) or `llvm.fsub` (float).
168	///
169	/// Integer subtractions use default overflow flags.
170	/// Float subtractions include fastmath flags.
171	pub(crate) fn convert_sub(
172	    ctx: &mut Context,
173	    rewriter: &mut DialectConversionRewriter,
174	    op: Ptr<Operation>,
175	    _operands_info: &OperandsInfo,
176	) -> Result<()> {
177	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
178	
179	    let llvm_op = if is_float_type(ctx, lhs) {
180	        let fsub = llvm::FSubOp::new(ctx, lhs, rhs);
181	        add_fastmath_flags(ctx, fsub.get_operation());
182	        fsub.get_operation()
183	    } else {
184	        let flags = IntegerOverflowFlagsAttr::default();
185	        llvm::SubOp::new_with_overflow_flag(ctx, lhs, rhs, flags).get_operation()
186	    };
187	
188	    rewriter.insert_operation(ctx, llvm_op);
189	    rewriter.replace_operation(ctx, op, llvm_op);
190	    Ok(())
191	}
