193	/// Convert `mir.mul` to `llvm.mul` (integer) or `llvm.fmul` (float).
194	///
195	/// Integer multiplications use default overflow flags.
196	/// Float multiplications include fastmath flags.
197	pub(crate) fn convert_mul(
198	    ctx: &mut Context,
199	    rewriter: &mut DialectConversionRewriter,
200	    op: Ptr<Operation>,
201	    _operands_info: &OperandsInfo,
202	) -> Result<()> {
203	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
204	
205	    let llvm_op = if is_float_type(ctx, lhs) {
206	        let fmul = llvm::FMulOp::new(ctx, lhs, rhs);
207	        add_fastmath_flags(ctx, fmul.get_operation());
208	        fmul.get_operation()
209	    } else {
210	        let flags = IntegerOverflowFlagsAttr::default();
211	        llvm::MulOp::new_with_overflow_flag(ctx, lhs, rhs, flags).get_operation()
212	    };
213	
214	    rewriter.insert_operation(ctx, llvm_op);
215	    rewriter.replace_operation(ctx, op, llvm_op);
216	    Ok(())
217	}
