219	/// Convert `mir.div` to `llvm.sdiv` (signed), `llvm.udiv` (unsigned), or `llvm.fdiv` (float).
220	///
221	/// Uses pre-conversion MIR operand type signedness to select between signed
222	/// and unsigned integer division.
223	pub(crate) fn convert_div(
224	    ctx: &mut Context,
225	    rewriter: &mut DialectConversionRewriter,
226	    op: Ptr<Operation>,
227	    operands_info: &OperandsInfo,
228	) -> Result<()> {
229	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
230	
231	    let llvm_op = if is_float_type(ctx, lhs) {
232	        let fdiv = llvm::FDivOp::new(ctx, lhs, rhs);
233	        add_fastmath_flags(ctx, fdiv.get_operation());
234	        fdiv.get_operation()
235	    } else if is_signed_int_op(ctx, op, operands_info)? {
236	        llvm::SDivOp::new(ctx, lhs, rhs).get_operation()
237	    } else {
238	        llvm::UDivOp::new(ctx, lhs, rhs).get_operation()
239	    };
240	
241	    rewriter.insert_operation(ctx, llvm_op);
242	    rewriter.replace_operation(ctx, op, llvm_op);
243	    Ok(())
244	}
