277	/// Convert `mir.checked_add` to `llvm.sadd.with.overflow` / `llvm.uadd.with.overflow`.
278	///
279	/// Uses the LLVM overflow intrinsic so the overflow flag reflects the actual
280	/// addition result rather than a hardcoded `false`. Returns `{iN, i1}`.
281	pub(crate) fn convert_checked_add(
282	    ctx: &mut Context,
283	    rewriter: &mut DialectConversionRewriter,
284	    op: Ptr<Operation>,
285	    operands_info: &OperandsInfo,
286	) -> Result<()> {
287	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
288	    let op_name = if is_signed_int_op(ctx, op, operands_info)? {
289	        "sadd"
290	    } else {
291	        "uadd"
292	    };
293	    convert_checked_binop_with_intrinsic(ctx, rewriter, op, lhs, rhs, op_name)
294	}
