334	/// Emit `llvm.<op_name>.with.overflow.iN` for a checked integer binop.
335	///
336	/// `op_name` is one of `sadd`, `uadd`, `ssub`, `usub`, `smul`, `umul`.
337	/// The LLVM intrinsic returns `{iN, i1}` directly, matching the converted MIR
338	/// result type. The `op` is replaced with the intrinsic call, so no
339	/// InsertValue reassembly is needed.
340	///
341	/// The pliron symbol name uses underscores (`llvm_sadd_with_overflow_i32`);
342	/// the llvm-export layer converts underscores back to dots on output.
343	fn convert_checked_binop_with_intrinsic(
344	    ctx: &mut Context,
345	    rewriter: &mut DialectConversionRewriter,
346	    op: Ptr<Operation>,
347	    lhs: Value,
348	    rhs: Value,
349	    op_name: &str,
350	) -> Result<()> {
351	    let loc = op.deref(ctx).loc();
352	    let lhs_ty = lhs.get_type(ctx);
353	
354	    let width = lhs_ty
355	        .deref(ctx)
356	        .downcast_ref::<IntegerType>()
357	        .map(|t| t.width())
358	        .ok_or_else(|| pliron::input_error!(loc, "checked binop: lhs must be an integer type"))?;
359	
360	    // Pliron identifiers use underscores; llvm-export converts to dots on output.
361	    let intrinsic_name = format!("llvm_{op_name}_with_overflow_i{width}");
362	
363	    let i1_ty = IntegerType::get(ctx, 1, Signedness::Signless);
364	    let struct_ty = llvm_types::StructType::get_unnamed(ctx, vec![lhs_ty, i1_ty.into()]);
365	    let func_ty = llvm_types::FuncType::get(ctx, struct_ty.into(), vec![lhs_ty, lhs_ty], false);
366	
367	    let call_op = call_intrinsic(ctx, rewriter, op, &intrinsic_name, func_ty, vec![lhs, rhs])?;
368	    rewriter.replace_operation(ctx, op, call_op);
369	    Ok(())
370	}
