372	// ============================================================================
373	// Shift operations
374	// ============================================================================
375	
376	/// Convert `mir.shr` to `llvm.ashr` (signed, arithmetic) or `llvm.lshr` (unsigned, logical).
377	///
378	/// Signed types use arithmetic shift right (sign-extending), unsigned types
379	/// use logical shift right (zero-filling). The shift count is cast and masked
380	/// before lowering because LLVM shifts are poison when the count is too large.
381	pub(crate) fn convert_shr(
382	    ctx: &mut Context,
383	    rewriter: &mut DialectConversionRewriter,
384	    op: Ptr<Operation>,
385	    operands_info: &OperandsInfo,
386	) -> Result<()> {
387	    let signed = is_signed_int_op(ctx, op, operands_info)?;
388	    convert_shift(ctx, rewriter, op, |ctx, lhs, rhs| {
389	        if signed {
390	            llvm::AShrOp::new(ctx, lhs, rhs).get_operation()
391	        } else {
392	            llvm::LShrOp::new(ctx, lhs, rhs).get_operation()
393	        }
394	    })
395	}
396	
397	/// Convert `mir.shl` to `llvm.shl` (shift left).
398	///
399	/// Includes default overflow flags. The shift count is cast and masked before
400	/// lowering because LLVM shifts are poison when the count is too large.
401	pub(crate) fn convert_shl(
402	    ctx: &mut Context,
403	    rewriter: &mut DialectConversionRewriter,
404	    op: Ptr<Operation>,
405	    _operands_info: &OperandsInfo,
406	) -> Result<()> {
407	    convert_shift(ctx, rewriter, op, |ctx, lhs, rhs| {
408	        let shl_op = llvm::ShlOp::new(ctx, lhs, rhs);
409	        let flags = IntegerOverflowFlagsAttr::default();
410	        shl_op.get_operation().deref_mut(ctx).attributes.set(
411	            llvm_export::op_interfaces::ATTR_KEY_INTEGER_OVERFLOW_FLAGS.clone(),
412	            flags,
413	        );
414	        shl_op.get_operation()
415	    })
416	}
417	
418	/// Common shift operation converter with Rust-compatible count handling.
419	///
420	/// LLVM requires the shift amount to have the same type as the value being
421	/// shifted. This function handles automatic widening (zext) or narrowing
422	/// (trunc) of the shift amount to match, then masks it with `bit_width - 1`.
423	/// That matches Rust's unchecked/release shift behavior and avoids LLVM poison
424	/// for oversized counts.
425	fn convert_shift<F>(
426	    ctx: &mut Context,
427	    rewriter: &mut DialectConversionRewriter,
428	    op: Ptr<Operation>,
429	    builder: F,
430	) -> Result<()>
431	where
432	    F: FnOnce(&mut Context, Value, Value) -> Ptr<Operation>,
433	{
434	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
435	
436	    let lhs_ty = lhs.get_type(ctx);
437	    let rhs_ty = rhs.get_type(ctx);
438	    let lhs_width = lhs_ty
439	        .deref(ctx)
440	        .downcast_ref::<IntegerType>()
441	        .ok_or_else(|| {
442	            pliron::input_error!(op.deref(ctx).loc(), "Shift value must be integer type")
443	        })?
444	        .width();
445	
446	    let rhs_casted = if lhs_ty != rhs_ty {
447	        let rhs_width = rhs_ty
448	            .deref(ctx)
449	            .downcast_ref::<IntegerType>()
450	            .ok_or_else(|| {
451	                pliron::input_error!(op.deref(ctx).loc(), "Shift amount must be integer type")
452	            })?
453	            .width();
454	
455	        let cast_op = if lhs_width > rhs_width {
456	            let zext = llvm::ZExtOp::new(ctx, rhs, lhs_ty);
457	            let nneg_key: pliron::identifier::Identifier = "llvm_nneg_flag".try_into().unwrap();
458	            zext.get_operation()
459	                .deref_mut(ctx)
460	                .attributes
461	                .set(nneg_key, pliron::builtin::attributes::BoolAttr::new(false));
462	            zext.get_operation()
463	        } else {
464	            llvm::TruncOp::new(ctx, rhs, lhs_ty).get_operation()
465	        };
466	        rewriter.insert_operation(ctx, cast_op);
467	        cast_op.deref(ctx).get_result(0)
468	    } else {
469	        rhs
470	    };
471	
472	    let rhs_masked = mask_shift_amount(ctx, rewriter, rhs_casted, lhs_ty, lhs_width);
473	    let llvm_op = builder(ctx, lhs, rhs_masked);
474	    rewriter.insert_operation(ctx, llvm_op);
475	    rewriter.replace_operation(ctx, op, llvm_op);
476	    Ok(())
477	}
478	
479	fn mask_shift_amount(
480	    ctx: &mut Context,
481	    rewriter: &mut DialectConversionRewriter,
482	    rhs: Value,
483	    lhs_ty: pliron::r#type::TypeHandle,
484	    lhs_width: u32,
485	) -> Value {
486	    use pliron::utils::apint::APInt;
487	    use std::num::NonZeroUsize;
488	
489	    let mask_ty = IntegerType::get(ctx, lhs_width, Signedness::Signless);
490	    let mask_attr = pliron::builtin::attributes::IntegerAttr::new(
491	        mask_ty,
492	        APInt::from_u128(
493	            u128::from(lhs_width - 1),
494	            NonZeroUsize::new(lhs_width as usize).unwrap(),
495	        ),
496	    );
497	    let mask_op = llvm::ConstantOp::new(ctx, mask_attr.into());
498	    rewriter.insert_operation(ctx, mask_op.get_operation());
499	    let mask_value = mask_op.get_operation().deref(ctx).get_result(0);
500	
501	    let and_op = llvm::AndOp::new(ctx, rhs, mask_value).get_operation();
502	    rewriter.insert_operation(ctx, and_op);
503	
504	    debug_assert_eq!(and_op.deref(ctx).get_result(0).get_type(ctx), lhs_ty);
505	    and_op.deref(ctx).get_result(0)
506	}
