512	/// Convert `mir.bitand` to `llvm.and`.
513	pub(crate) fn convert_bitand(
514	    ctx: &mut Context,
515	    rewriter: &mut DialectConversionRewriter,
516	    op: Ptr<Operation>,
517	    _operands_info: &OperandsInfo,
518	) -> Result<()> {
519	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
520	    let llvm_op = llvm::AndOp::new(ctx, lhs, rhs).get_operation();
521	    rewriter.insert_operation(ctx, llvm_op);
522	    rewriter.replace_operation(ctx, op, llvm_op);
523	    Ok(())
524	}
