526	/// Convert `mir.bitor` to `llvm.or`.
527	pub(crate) fn convert_bitor(
528	    ctx: &mut Context,
529	    rewriter: &mut DialectConversionRewriter,
530	    op: Ptr<Operation>,
531	    _operands_info: &OperandsInfo,
532	) -> Result<()> {
533	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
534	    let llvm_op = llvm::OrOp::new(ctx, lhs, rhs).get_operation();
535	    rewriter.insert_operation(ctx, llvm_op);
536	    rewriter.replace_operation(ctx, op, llvm_op);
537	    Ok(())
538	}
539	
540	/// Convert `mir.bitxor` to `llvm.xor`.
541	pub(crate) fn convert_bitxor(
542	    ctx: &mut Context,
543	    rewriter: &mut DialectConversionRewriter,
544	    op: Ptr<Operation>,
545	    _operands_info: &OperandsInfo,
546	) -> Result<()> {
547	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
548	    let llvm_op = llvm::XorOp::new(ctx, lhs, rhs).get_operation();
549	    rewriter.insert_operation(ctx, llvm_op);
550	    rewriter.replace_operation(ctx, op, llvm_op);
551	    Ok(())
552	}
553	
554	/// Convert `mir.neg` to `llvm.fneg` for floats or `0 - x` for integers.
555	///
556	/// LLVM has a dedicated floating-point negation op. Integer negation is a
557	/// subtraction from zero, which also matches how LLVM represents integer `neg`.
558	pub(crate) fn convert_neg(
559	    ctx: &mut Context,
560	    rewriter: &mut DialectConversionRewriter,
561	    op: Ptr<Operation>,
562	    _operands_info: &OperandsInfo,
563	) -> Result<()> {
564	    use pliron::utils::apint::APInt;
565	    use std::num::NonZeroUsize;
566	
567	    let operand = op.deref(ctx).get_operand(0);
568	    let operand_ty = operand.get_type(ctx);
569	
570	    let llvm_op = if is_float_type(ctx, operand) {
571	        llvm::FNegOp::new_with_fast_math_flags(ctx, operand, FastmathFlagsAttr::default())
572	            .get_operation()
573	    } else {
574	        let width = operand_ty
575	            .deref(ctx)
576	            .downcast_ref::<IntegerType>()
577	            .ok_or_else(|| {
578	                pliron::input_error!(
579	                    op.deref(ctx).loc(),
580	                    "NEG only supports integer or float types"
581	                )
582	            })?
583	            .width();
584	
585	        let zero_ty = IntegerType::get(ctx, width, Signedness::Signless);
586	        let zero_attr = IntegerAttr::new(
587	            zero_ty,
588	            APInt::from_u128(0, NonZeroUsize::new(width as usize).unwrap()),
589	        );
590	        let zero_op = llvm::ConstantOp::new(ctx, zero_attr.into()).get_operation();
591	        rewriter.insert_operation(ctx, zero_op);
592	        let zero = zero_op.deref(ctx).get_result(0);
593	
594	        let flags = IntegerOverflowFlagsAttr::default();
595	        llvm::SubOp::new_with_overflow_flag(ctx, zero, operand, flags).get_operation()
596	    };
597	
598	    rewriter.insert_operation(ctx, llvm_op);
599	    rewriter.replace_operation(ctx, op, llvm_op);
600	    Ok(())
601	}
602	
603	/// Convert `mir.not` to `llvm.xor` with all-ones constant.
604	///
605	/// LLVM has no direct NOT instruction. Bitwise NOT is implemented as
606	/// XOR with -1 (all bits set). The constant is created with the same
607	/// bit width as the operand.
608	pub(crate) fn convert_not(
609	    ctx: &mut Context,
610	    rewriter: &mut DialectConversionRewriter,
611	    op: Ptr<Operation>,
612	    _operands_info: &OperandsInfo,
613	) -> Result<()> {
614	    use pliron::utils::apint::APInt;
615	    use std::num::NonZeroUsize;
616	
617	    let operand = op.deref(ctx).get_operand(0);
618	
619	    let ty = operand.get_type(ctx);
620	    let width = ty
621	        .deref(ctx)
622	        .downcast_ref::<IntegerType>()
623	        .ok_or_else(|| {
624	            pliron::input_error!(op.deref(ctx).loc(), "NOT only supports integer types")
625	        })?
626	        .width();
627	
628	    // Create all-ones constant (-1)
629	    let llvm_ty = IntegerType::get(ctx, width, Signedness::Signless);
630	    let apint = APInt::from_i64(-1, NonZeroUsize::new(width as usize).unwrap());
631	    let attr = pliron::builtin::attributes::IntegerAttr::new(llvm_ty, apint);
632	    let ones_const = llvm::ConstantOp::new(ctx, attr.into()).get_operation();
633	    rewriter.insert_operation(ctx, ones_const);
634	    let ones_val = ones_const.deref(ctx).get_result(0);
635	
636	    let xor_op = llvm::XorOp::new(ctx, operand, ones_val).get_operation();
637	    rewriter.insert_operation(ctx, xor_op);
638	    rewriter.replace_operation(ctx, op, xor_op);
639	    Ok(())
640	}
641	
642	// ============================================================================
643	// Comparison operations
644	// ============================================================================
645	
646	/// Convert MIR comparison to `llvm.icmp` (integer) or `llvm.fcmp` (float).
647	///
648	/// Integer comparisons use signed or unsigned predicates based on
649	/// pre-conversion MIR operand type signedness.
650	///
651	/// Float predicates mirror rustc_codegen_ssa's `bin_op_to_fcmp_predicate`:
652	/// `Eq -> oeq`, `Lt -> olt`, `Le -> ole`, `Gt -> ogt`, `Ge -> oge` (ordered,
653	/// false if either operand is NaN), and `Ne -> une` (UNordered, true if
654	/// either operand is NaN) so that `a != b` equals `!(a == b)` per Rust
655	/// `PartialEq` semantics. An ordered `one` here folds the canonical NaN
656	/// check `x != x` to `false` (issue #123).
657	pub(crate) fn convert_cmp(
658	    ctx: &mut Context,
659	    rewriter: &mut DialectConversionRewriter,
660	    op: Ptr<Operation>,
661	    operands_info: &OperandsInfo,
662	    signed_pred: ICmpPredicateAttr,
663	    unsigned_pred: ICmpPredicateAttr,
664	    float_pred: FCmpPredicateAttr,
665	) -> Result<()> {
666	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
667	
668	    let llvm_op = if is_float_type(ctx, lhs) {
669	        // Upstream FCmpOp carries the FastMathFlags interface, whose verifier
670	        // requires the `llvm_fast_math_flags` attribute to be present (it is
671	        // not set by `FCmpOp::new`). Attach default flags, as the float
672	        // arithmetic ops do.
673	        let fcmp = llvm::FCmpOp::new(ctx, float_pred, lhs, rhs).get_operation();
674	        add_fastmath_flags(ctx, fcmp);
675	        fcmp
676	    } else {
677	        let pred = if is_signed_int_op(ctx, op, operands_info)? {
678	            signed_pred
679	        } else {
680	            unsigned_pred
681	        };
682	        llvm::ICmpOp::new(ctx, pred, lhs, rhs).get_operation()
683	    };
684	
685	    rewriter.insert_operation(ctx, llvm_op);
686	    rewriter.replace_operation(ctx, op, llvm_op);
687	    Ok(())
688	}
689	
690	pub(crate) fn convert_three_way_cmp(
691	    ctx: &mut Context,
692	    rewriter: &mut DialectConversionRewriter,
693	    op: Ptr<Operation>,
694	    operands_info: &OperandsInfo,
695	) -> Result<()> {
696	    let (lhs, rhs) = get_binary_operands(op, ctx)?;
697	    if is_float_type(ctx, lhs) {
698	        // rustc never emits BinOp::Cmp for floats: f32/f64 are not Ord,
699	        // and f32::total_cmp lowers to integer bit-twiddling, not Cmp.
700	        // An OLT/OGT select chain would also miscompile: NaN compares
701	        // false on both predicates and would silently yield Equal.
702	        let loc = op.deref(ctx).loc();
703	        return pliron::input_err!(
704	            loc,
705	            "BinOp::Cmp on floats is never emitted by rustc; total-order lowering unimplemented"
706	        );
707	    }
708	    let is_signed = is_signed_int_op(ctx, op, operands_info)?;
709	
710	    let is_lt = emit_cmp_value(ctx, rewriter, op, lhs, rhs, is_signed, true);
711	    let is_gt = emit_cmp_value(ctx, rewriter, op, lhs, rhs, is_signed, false);
712	
713	    let mir_result_ty = op.deref(ctx).get_result(0).get_type(ctx);
714	    let loc = op.deref(ctx).loc();
715	    let (discr_ty, variant_discriminants) = {
716	        let mir_result_ty_obj = mir_result_ty.deref(ctx);
717	        let enum_ty = mir_result_ty_obj
718	            .downcast_ref::<dialect_mir::types::MirEnumType>()
719	            .ok_or_else(|| pliron::input_error!(loc.clone(), "mir.cmp result must be an enum"))?;
720	        (
721	            enum_ty.discriminant_ty,
722	            enum_ty.variant_discriminants.clone(),
723	        )
724	    };
725	    let llvm_result_ty =
726	        convert_type(ctx, mir_result_ty).map_err(|e| pliron::input_error!(loc.clone(), "{e}"))?;
727	    let llvm_discr_ty =
728	        convert_type(ctx, discr_ty).map_err(|e| pliron::input_error!(loc.clone(), "{e}"))?;
729	
730	    if variant_discriminants.len() != 3 {
731	        return pliron::input_err_noloc!("mir.cmp result enum must have three discriminants");
732	    }
733	
734	    let less = emit_discriminant_const(ctx, rewriter, llvm_discr_ty, variant_discriminants[0])?;
735	    let equal = emit_discriminant_const(ctx, rewriter, llvm_discr_ty, variant_discriminants[1])?;
736	    let greater = emit_discriminant_const(ctx, rewriter, llvm_discr_ty, variant_discriminants[2])?;
737	
738	    let gt_or_equal = llvm::SelectOp::new(ctx, is_gt, greater, equal).get_operation();
739	    rewriter.insert_operation(ctx, gt_or_equal);
740	    let gt_or_equal_val = gt_or_equal.deref(ctx).get_result(0);
741	
742	    let selected = llvm::SelectOp::new(ctx, is_lt, less, gt_or_equal_val).get_operation();
743	    rewriter.insert_operation(ctx, selected);
744	    let selected_discr = selected.deref(ctx).get_result(0);
745	
746	    let undef = llvm::UndefOp::new(ctx, llvm_result_ty);
747	    rewriter.insert_operation(ctx, undef.get_operation());
748	    let enum_value = undef.get_operation().deref(ctx).get_result(0);
749	
750	    // The tag slot comes from the enum slot map (for Ordering it is slot
751	    // 0, but the index source must be the map, never a literal).
752	    let tag_slot = crate::convert::types::build_enum_slot_map(ctx, mir_result_ty)
753	        .map_err(|e| pliron::input_error!(loc.clone(), "{e}"))?
754	        .tag_slot;
755	    let insert_discr = llvm::InsertValueOp::new(ctx, enum_value, selected_discr, vec![tag_slot]);
756	    rewriter.insert_operation(ctx, insert_discr.get_operation());
757	    rewriter.replace_operation(ctx, op, insert_discr.get_operation());
758	    Ok(())
759	}
760	
761	/// Emit one integer comparison leg of the three-way compare.
762	///
763	/// Float operands are rejected by [`convert_three_way_cmp`] before this
764	/// runs, so only integer predicates are needed.
765	fn emit_cmp_value(
766	    ctx: &mut Context,
767	    rewriter: &mut DialectConversionRewriter,
768	    op: Ptr<Operation>,
769	    lhs: Value,
770	    rhs: Value,
771	    is_signed: bool,
772	    less: bool,
773	) -> Value {
774	    let pred = match (less, is_signed) {
775	        (true, true) => ICmpPredicateAttr::SLT,
776	        (true, false) => ICmpPredicateAttr::ULT,
777	        (false, true) => ICmpPredicateAttr::SGT,
778	        (false, false) => ICmpPredicateAttr::UGT,
779	    };
780	    let cmp_op = llvm::ICmpOp::new(ctx, pred, lhs, rhs).get_operation();
781	    cmp_op.deref_mut(ctx).set_loc(op.deref(ctx).loc());
782	    rewriter.insert_operation(ctx, cmp_op);
783	    cmp_op.deref(ctx).get_result(0)
784	}
785	
786	fn emit_discriminant_const(
787	    ctx: &mut Context,
788	    rewriter: &mut DialectConversionRewriter,
789	    discr_ty: pliron::r#type::TypeHandle,
790	    value: u64,
791	) -> Result<Value> {
792	    use pliron::utils::apint::APInt;
793	    use std::num::NonZeroUsize;
794	
795	    let width = discr_ty
796	        .deref(ctx)
797	        .downcast_ref::<IntegerType>()
798	        .ok_or_else(|| pliron::input_error_noloc!("Ordering discriminant must be integer"))?
799	        .width();
800	    let signless_ty = IntegerType::get(ctx, width, Signedness::Signless);
801	    let attr = IntegerAttr::new(
802	        signless_ty,
803	        APInt::from_u64(value, NonZeroUsize::new(width as usize).unwrap()),
804	    );
805	    let const_op = llvm::ConstantOp::new(ctx, attr.into()).get_operation();
806	    rewriter.insert_operation(ctx, const_op);
807	    Ok(const_op.deref(ctx).get_result(0))
808	}
809	
810	// Conversion coverage: `tests/lowering_test.rs::test_cmp_predicate_lowering`
811	// locks the comparison predicate table end-to-end; the two unit tests in
812	// this module lock the contract-only fast-math flag on float arithmetic.
813	
814	#[cfg(test)]
815	mod tests {
816	    use super::*;
817	    use crate::convert::ops::test_util::*;
818	    use dialect_mir::ops as mir;
819	    use llvm_export::attributes::FastmathFlags;
820	    use llvm_export::op_interfaces::FastMathFlags as FastMathFlagsTrait;
821	    use llvm_export::ops as llvm;
822	    use pliron::r#type::TypeHandle;
823	
824	    /// A float `mir.mul` lowers to `llvm.fmul` carrying exactly the `contract`
825	    /// fast-math flag: enough for the NVPTX backend to fuse a feeding multiply
826	    /// into `fma.rn.f32`, with none of the reassoc/nnan/ninf/nsz relaxations.
827	    #[test]
828	    fn convert_mul_float_sets_only_contract_flag() {
829	        let mut ctx = make_ctx();
830	        let f32_ty: TypeHandle = pliron::builtin::types::FP32Type::get(&ctx).into();
831	
832	        let (module_ptr, block) = build_kernel(&mut ctx, vec![f32_ty, f32_ty], vec![]);
833	        let lhs = block.deref(&ctx).get_argument(0);
834	        let rhs = block.deref(&ctx).get_argument(1);
835	
836	        let mul_op = Operation::new(
837	            &mut ctx,
838	            mir::MirMulOp::get_concrete_op_info(),
839	            vec![f32_ty],
840	            vec![lhs, rhs],
841	            vec![],
842	            0,
843	        );
844	        mul_op.insert_at_back(block, &ctx);
845	        append_mir_return(&mut ctx, block, vec![]);
846	
847	        crate::lower_mir_to_llvm(&mut ctx, module_ptr).expect("lowering failed");
848	
849	        let body = kernel_blocks(&ctx, module_ptr);
850	        let fmul = find_first::<llvm::FMulOp>(&ctx, &body).expect("expected one llvm.fmul");
851	        assert_eq!(
852	            fmul.fast_math_flags(&ctx).0,
853	            FastmathFlags::CONTRACT,
854	            "float mul must carry exactly the contract fast-math flag"
855	        );
856	    }
857	
858	    /// The same contraction flag is set on `mir.add` -> `llvm.fadd`.
859	    #[test]
860	    fn convert_add_float_sets_only_contract_flag() {
861	        let mut ctx = make_ctx();
862	        let f32_ty: TypeHandle = pliron::builtin::types::FP32Type::get(&ctx).into();
863	
864	        let (module_ptr, block) = build_kernel(&mut ctx, vec![f32_ty, f32_ty], vec![]);
865	        let lhs = block.deref(&ctx).get_argument(0);
866	        let rhs = block.deref(&ctx).get_argument(1);
867	
868	        let add_op = Operation::new(
869	            &mut ctx,
870	            mir::MirAddOp::get_concrete_op_info(),
871	            vec![f32_ty],
872	            vec![lhs, rhs],
873	            vec![],
874	            0,
875	        );
876	        add_op.insert_at_back(block, &ctx);
877	        append_mir_return(&mut ctx, block, vec![]);
878	
879	        crate::lower_mir_to_llvm(&mut ctx, module_ptr).expect("lowering failed");
880	
881	        let body = kernel_blocks(&ctx, module_ptr);
882	        let fadd = find_first::<llvm::FAddOp>(&ctx, &body).expect("expected one llvm.fadd");
883	        assert_eq!(
884	            fadd.fast_math_flags(&ctx).0,
885	            FastmathFlags::CONTRACT,
886	            "float add must carry exactly the contract fast-math flag"
887	        );
888	    }
889	
890	    /// Disabling contraction removes the IR-level permission from both sides
891	    /// of a multiply-add chain. The backend command-line gate alone is not
892	    /// sufficient when either instruction still carries `contract`.
893	    #[test]
894	    fn no_fma_contraction_omits_contract_flags_from_mul_add_sub_chains() {
895	        let mut ctx = make_ctx();
896	        let f32_ty: TypeHandle = pliron::builtin::types::FP32Type::get(&ctx).into();
897	
898	        let (module_ptr, block) = build_kernel(&mut ctx, vec![f32_ty, f32_ty, f32_ty], vec![]);
899	        let lhs = block.deref(&ctx).get_argument(0);
900	        let rhs = block.deref(&ctx).get_argument(1);
901	        let addend = block.deref(&ctx).get_argument(2);
902	
903	        let mul_op = Operation::new(
904	            &mut ctx,
905	            mir::MirMulOp::get_concrete_op_info(),
906	            vec![f32_ty],
907	            vec![lhs, rhs],
908	            vec![],
909	            0,
910	        );
911	        let product = mul_op.deref(&ctx).get_result(0);
912	        mul_op.insert_at_back(block, &ctx);
913	
914	        let add_op = Operation::new(
915	            &mut ctx,
916	            mir::MirAddOp::get_concrete_op_info(),
917	            vec![f32_ty],
918	            vec![product, addend],
919	            vec![],
920	            0,
921	        );
922	        add_op.insert_at_back(block, &ctx);
923	
924	        let sub_op = Operation::new(
925	            &mut ctx,
926	            mir::MirSubOp::get_concrete_op_info(),
927	            vec![f32_ty],
928	            vec![product, addend],
929	            vec![],
930	            0,
931	        );
932	        sub_op.insert_at_back(block, &ctx);
933	        append_mir_return(&mut ctx, block, vec![]);
934	
935	        crate::lower_mir_to_llvm_with_options(
936	            &mut ctx,
937	            module_ptr,
938	            crate::LoweringOptions {
939	                allow_fma_contraction: false,
940	            },
941	        )
942	        .expect("lowering failed");
943	
944	        let body = kernel_blocks(&ctx, module_ptr);
945	        let fmul = find_first::<llvm::FMulOp>(&ctx, &body).expect("expected one llvm.fmul");
946	        let fadd = find_first::<llvm::FAddOp>(&ctx, &body).expect("expected one llvm.fadd");
947	        let fsub = find_first::<llvm::FSubOp>(&ctx, &body).expect("expected one llvm.fsub");
948	        assert_eq!(fmul.fast_math_flags(&ctx).0, FastmathFlags::empty());
949	        assert_eq!(fadd.fast_math_flags(&ctx).0, FastmathFlags::empty());
950	        assert_eq!(fsub.fast_math_flags(&ctx).0, FastmathFlags::empty());
951	    }
952	}
