73	            operands.len()
74	        );
75	    }
76	
77	    let f32_ty = FP32Type::get(ctx);
78	    let result_ty = llvm_types::StructType::get_unnamed(ctx, vec![f32_ty.into(); 4]);
79	    let template = concat!(
80	        "mma.sync.aligned.m16n8k16.row.col.f32.bf16.bf16.f32 ",
81	        "{$0, $1, $2, $3}, ",
82	        "{$8, $9, $10, $11}, ",
83	        "{$12, $13}, ",
84	        "{$4, $5, $6, $7};"
85	    );
86	    let constraints = "=f,=f,=f,=f,f,f,f,f,r,r,r,r,r,r";
