        ctx,
        rewriter,
        result_ty.into(),
        operands,
        "mma.sync.aligned.m8n8k4.row.col.f64.f64.f64.f64 \
         {$0, $1}, {$4}, {$5}, {$2, $3};",
        "=d,=d,d,d,d,d",
    );

    let aggregate = inline_asm.deref(ctx).get_result(0);
    let mut results = Vec::with_capacity(2);
    for index in 0..2 {
