86	/// Convert `mir.store` to `llvm.store`.
87	///
88	/// Operand order: `[ptr, value]` - stores `value` to address `ptr`.
89	/// No result is produced (store is a side effect).
90	pub(crate) fn convert_store(
91	    ctx: &mut Context,
92	    rewriter: &mut DialectConversionRewriter,
93	    op: Ptr<Operation>,
94	    _operands_info: &OperandsInfo,
95	) -> Result<()> {
96	    let operands: Vec<_> = op.deref(ctx).operands().collect();
97	
98	    let (ptr, val) = match operands.as_slice() {
99	        [ptr, val] => (*ptr, *val),
100	        _ => {
101	            return pliron::input_err_noloc!("Store operation requires exactly 2 operands");
102	        }
103	    };
104	
105	    let llvm_store = llvm::StoreOp::new(ctx, val, ptr);
106	    if dialect_mir::ops::MirStoreOp::new(op).is_volatile(ctx) {
107	        llvm_export::ops::set_op_volatile(ctx, llvm_store.get_operation(), true);
108	    }
109	    copy_alignment(ctx, op, llvm_store.get_operation());
110	    rewriter.insert_operation(ctx, llvm_store.get_operation());
111	    rewriter.erase_operation(ctx, op);
112	    Ok(())
113	}
