119	/// exporter can emit `align N`.
120	fn copy_alignment(ctx: &mut Context, mir_op: Ptr<Operation>, llvm_op: Ptr<Operation>) {
121	    if let Some(align) = llvm_export::ops::op_alignment(ctx, mir_op) {
122	        llvm_export::ops::set_op_alignment(ctx, llvm_op, align);
