140	/// Convert `mir.memcpy` to the matching `llvm.memcpy.p<dst>.p<src>.i<bits>`.
141	///
142	/// MIR's count is measured in pointee elements, while LLVM's memcpy intrinsic
143	/// expects bytes. The pre-conversion destination pointer type still carries the
144	/// MIR pointee, so use it to scale the count before emitting the call.
145	///
146	/// The intrinsic name is an overload: LLVM encodes each pointer's address
147	/// space and the length width into it, and its verifier rejects a call whose
148	/// argument types disagree with the name. Today every pointer reaching a
149	/// `copy_nonoverlapping` is a Rust raw pointer, which cuda-oxide normalizes to
150	/// the generic address space (an `addrspacecast` is inserted when the raw
151	/// pointer is formed), so the operands are always `p0` and `i64`. We still
152	/// derive the suffix from the real operand types rather than hardcoding
153	/// `p0.p0.i64`: it matches how every other overloaded intrinsic is named here
154	/// (`ctpop`, `fptosi.sat`, ...), and it keeps this lowering correct if raw
155	/// pointers ever start carrying a non-generic address space.
156	pub(crate) fn convert_memcpy(
157	    ctx: &mut Context,
158	    rewriter: &mut DialectConversionRewriter,
159	    op: Ptr<Operation>,
160	    operands_info: &OperandsInfo,
161	) -> Result<()> {
162	    let operands: Vec<_> = op.deref(ctx).operands().collect();
163	    let (dst, src, count) = match operands.as_slice() {
164	        [dst, src, count] => (*dst, *src, *count),
165	        _ => {
166	            return pliron::input_err_noloc!("Memcpy operation requires exactly 3 operands");
167	        }
168	    };
169	
170	    let pointee = {
171	        let dst_ptr_ty = operands_info
172	            .lookup_most_recent_of_type::<MirPtrType>(ctx, dst)
173	            .ok_or_else(|| {
174	                pliron::create_error!(
175	                    op.deref(ctx).loc(),
176	                    pliron::result::ErrorKind::VerificationFailed,
177	                    pliron::result::StringError(
178	                        "Memcpy destination must be a MIR pointer before lowering".to_string()
179	                    )
180	                )
181	            })?;
182	        dst_ptr_ty.pointee
183	    };
184	    let elem_ty = convert_type(ctx, pointee).map_err(anyhow_to_pliron)?;
185	    let elem_size = get_type_size(ctx, elem_ty);
186	
187	    let bytes = if elem_size == 1 {
188	        count
189	    } else {
190	        let count_ty = count.get_type(ctx);
191	        let bits = count_ty
192	            .deref(ctx)
193	            .downcast_ref::<IntegerType>()
194	            .map(|ty| ty.width())
195	            .unwrap_or(64);
196	        let count_int_ty = IntegerType::get(ctx, bits, Signedness::Signless);
197	        let size_attr: AttrObj = IntegerAttr::new(
198	            count_int_ty,
199	            APInt::from_u64(
200	                elem_size,
201	                std::num::NonZeroUsize::new(bits as usize).unwrap(),
202	            ),
203	        )
204	        .into();
205	        let size_const = llvm::ConstantOp::new(ctx, size_attr);
206	        let size_val = size_const.get_operation().deref(ctx).get_result(0);
207	        rewriter.insert_operation(ctx, size_const.get_operation());
208	
209	        let flags = IntegerOverflowFlagsAttr::default();
210	        let mul = llvm::MulOp::new_with_overflow_flag(ctx, count, size_val, flags);
211	        rewriter.insert_operation(ctx, mul.get_operation());
212	        mul.get_operation().deref(ctx).get_result(0)
213	    };
214	
215	    let i1_ty = IntegerType::get(ctx, 1, Signedness::Signless);
216	    let false_attr: AttrObj = IntegerAttr::new(
217	        i1_ty,
218	        APInt::from_u64(0, std::num::NonZeroUsize::new(1).unwrap()),
219	    )
220	    .into();
221	    let volatile = llvm::ConstantOp::new(ctx, false_attr);
222	    rewriter.insert_operation(ctx, volatile.get_operation());
223	    let volatile_val = volatile.get_operation().deref(ctx).get_result(0);
224	
225	    let void_ty = VoidType::get(ctx);
226	    let func_ty = FuncType::get(
227	        ctx,
228	        void_ty.into(),
229	        vec![
230	            dst.get_type(ctx),
231	            src.get_type(ctx),
232	            bytes.get_type(ctx),
233	            volatile_val.get_type(ctx),
234	        ],
235	        false,
236	    );
237	    let parent_block = op.deref(ctx).get_parent_block().ok_or_else(|| {
238	        pliron::create_error!(
239	            op.deref(ctx).loc(),
240	            pliron::result::ErrorKind::VerificationFailed,
241	            pliron::result::StringError("Memcpy operation has no parent block".to_string())
242	        )
243	    })?;
244	    // Derive the overload suffix from the real (already type-converted)
245	    // operands so the name can never disagree with the argument types.
246	    let dst_ty = dst.get_type(ctx);
247	    let dst_as = dst_ty
248	        .deref(ctx)
249	        .downcast_ref::<llvm_export::types::PointerType>()
250	        .map(|pt| pt.address_space())
251	        .unwrap_or(0);
252	    let src_ty = src.get_type(ctx);
253	    let src_as = src_ty
254	        .deref(ctx)
255	        .downcast_ref::<llvm_export::types::PointerType>()
256	        .map(|pt| pt.address_space())
257	        .unwrap_or(0);
258	    let len_bits = bytes
259	        .get_type(ctx)
260	        .deref(ctx)
261	        .downcast_ref::<IntegerType>()
262	        .map(|t| t.width())
263	        .unwrap_or(64);
264	    let intrinsic_name = format!("llvm_memcpy_p{dst_as}_p{src_as}_i{len_bits}");
265	    helpers::ensure_intrinsic_declared(ctx, parent_block, &intrinsic_name, func_ty)
266	        .map_err(anyhow_to_pliron)?;
267	
268	    let callee: Identifier = intrinsic_name.as_str().try_into().map_err(|e| {
269	        pliron::create_error!(
270	            op.deref(ctx).loc(),
271	            pliron::result::ErrorKind::VerificationFailed,
272	            pliron::result::StringError(format!("Invalid memcpy intrinsic name: {e:?}"))
273	        )
274	    })?;
275	    let call = llvm::CallOp::new(
276	        ctx,
277	        CallOpCallable::Direct(callee),
278	        func_ty,
279	        vec![dst, src, bytes, volatile_val],
280	    );
281	    rewriter.insert_operation(ctx, call.get_operation());
282	    rewriter.erase_operation(ctx, op);
283	    Ok(())
284	}
