290	pub(crate) fn convert_load(
291	    ctx: &mut Context,
292	    rewriter: &mut DialectConversionRewriter,
293	    op: Ptr<Operation>,
294	    _operands_info: &OperandsInfo,
295	) -> Result<()> {
296	    let ptr = op.deref(ctx).get_operand(0);
297	    let result_ty = op.deref(ctx).get_result(0).get_type(ctx);
298	    let llvm_ty = convert_type(ctx, result_ty).map_err(anyhow_to_pliron)?;
299	
300	    let llvm_load = llvm::LoadOp::new(ctx, ptr, llvm_ty);
301	    if dialect_mir::ops::MirLoadOp::new(op).is_volatile(ctx) {
302	        llvm_export::ops::set_op_volatile(ctx, llvm_load.get_operation(), true);
303	    }
304	    copy_alignment(ctx, op, llvm_load.get_operation());
305	    rewriter.insert_operation(ctx, llvm_load.get_operation());
306	    rewriter.replace_operation(ctx, op, llvm_load.get_operation());
307	
308	    Ok(())
309	}
