311	/// Convert `mir.dbg_value` to the LLVM-export debug marker.
312	///
313	/// The op is still debug-only after lowering. The textual LLVM exporter later
314	/// prints it as an `llvm.dbg.value` intrinsic call.
315	pub(crate) fn convert_dbg_value(
316	    ctx: &mut Context,
317	    rewriter: &mut DialectConversionRewriter,
318	    op: Ptr<Operation>,
319	    _operands_info: &OperandsInfo,
320	) -> Result<()> {
321	    let value = op.deref(ctx).get_operand(0);
322	    let loc = op.deref(ctx).loc().clone();
323	    let llvm_dbg_value = llvm::DebugValueOp::new(ctx, value);
324	    llvm_dbg_value.get_operation().deref_mut(ctx).set_loc(loc);
325	    copy_debug_local_variable(ctx, op, llvm_dbg_value.get_operation());
326	    rewriter.insert_operation(ctx, llvm_dbg_value.get_operation());
327	    rewriter.erase_operation(ctx, op);
328	    Ok(())
329	}
