331	/// Convert `mir.alloca` to `llvm.alloca`.
332	///
333	/// `mir.alloca` carries its element type on the result pointer's pointee, and
334	/// emits a single-element stack slot of that type. We therefore convert the
335	/// pointee to an LLVM type and emit `llvm.alloca <pointee_ty>, i32 1`.
336	///
337	/// No value is stored into the slot; that is the caller's job via subsequent
338	/// `mir.store` / `llvm.store` ops. This matches the mem2reg-ready translator
339	/// model where every local is backed by one alloca in the entry block and
340	/// defs/uses go through `store`/`load` rather than SSA values.
341	pub(crate) fn convert_alloca(
342	    ctx: &mut Context,
343	    rewriter: &mut DialectConversionRewriter,
344	    op: Ptr<Operation>,
345	    _operands_info: &OperandsInfo,
346	) -> Result<()> {
347	    let result_ty = op.deref(ctx).get_result(0).get_type(ctx);
348	    let mir_pointee = {
349	        let ty_ref = result_ty.deref(ctx);
350	        let mir_ptr = ty_ref.downcast_ref::<MirPtrType>().ok_or_else(|| {
351	            anyhow_to_pliron(anyhow::anyhow!(
352	                "MirAllocaOp result must be MirPtrType (enforced by verifier)"
353	            ))
354	        })?;
355	        mir_ptr.pointee
356	    };
357	    let llvm_pointee = convert_type(ctx, mir_pointee).map_err(anyhow_to_pliron)?;
358	
359	    let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
360	    let one_apint =
361	        pliron::utils::apint::APInt::from_i64(1, std::num::NonZeroUsize::new(32).unwrap());
362	    let one_attr = pliron::builtin::attributes::IntegerAttr::new(i32_ty, one_apint);
363	    let one_const = llvm::ConstantOp::new(ctx, one_attr.into());
364	    rewriter.insert_operation(ctx, one_const.get_operation());
365	    let one_val = one_const.get_operation().deref(ctx).get_result(0);
366	
367	    let alloca = llvm::AllocaOp::new(ctx, llvm_pointee, one_val);
368	    copy_alignment(ctx, op, alloca.get_operation());
369	    copy_debug_local_variable(ctx, op, alloca.get_operation());
370	    rewriter.insert_operation(ctx, alloca.get_operation());
371	    rewriter.replace_operation(ctx, op, alloca.get_operation());
372	
373	    Ok(())
374	}
