376	/// Convert `mir.ref` — materialize the operand in stack memory via alloca+store.
377	///
378	/// `mir.ref` creates a pointer to an SSA value. In SSA form, values don't have
379	/// addresses, so we must place the value in memory to obtain a pointer.
380	/// This applies to all types: scalars (e.g. `&factor` where factor is `u32`),
381	/// aggregates (e.g. `&closure_env`), and pointers (e.g. `&&T`).
382	pub(crate) fn convert_ref(
383	    ctx: &mut Context,
384	    rewriter: &mut DialectConversionRewriter,
385	    op: Ptr<Operation>,
386	    _operands_info: &OperandsInfo,
387	) -> Result<()> {
388	    let operand = op.deref(ctx).get_operand(0);
389	    let operand_ty = operand.get_type(ctx);
390	
391	    let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
392	    let one_apint =
393	        pliron::utils::apint::APInt::from_i64(1, std::num::NonZeroUsize::new(32).unwrap());
394	    let one_attr = pliron::builtin::attributes::IntegerAttr::new(i32_ty, one_apint);
395	    let one_const = llvm::ConstantOp::new(ctx, one_attr.into());
396	    rewriter.insert_operation(ctx, one_const.get_operation());
397	    let one_val = one_const.get_operation().deref(ctx).get_result(0);
398	
399	    let alloca = llvm::AllocaOp::new(ctx, operand_ty, one_val);
400	    // Propagate alignment stamped by the pre-pass (covers repr(align(N))
401	    // structs). Without this, the synthesised alloca would be under-aligned
402	    // relative to any loads/stores that claim the struct's true alignment.
403	    copy_alignment(ctx, op, alloca.get_operation());
404	    rewriter.insert_operation(ctx, alloca.get_operation());
405	    let alloca_ptr = alloca.get_operation().deref(ctx).get_result(0);
406	
407	    let store = llvm::StoreOp::new(ctx, operand, alloca_ptr);
408	    copy_alignment(ctx, op, store.get_operation());
409	    rewriter.insert_operation(ctx, store.get_operation());
410	
411	    rewriter.replace_operation_with_values(ctx, op, vec![alloca_ptr]);
412	
413	    Ok(())
414	}
