416	/// Convert `mir.ptr_offset` to `llvm.getelementptr`.
417	///
418	/// Operands: `[ptr, offset]` where offset is an integer index.
419	/// Uses the pointee type from the MIR pointer type for element sizing.
420	/// Falls back to i8 element type if pointee type cannot be determined.
421	pub(crate) fn convert_ptr_offset(
422	    ctx: &mut Context,
423	    rewriter: &mut DialectConversionRewriter,
424	    op: Ptr<Operation>,
425	    operands_info: &OperandsInfo,
426	) -> Result<()> {
427	    let operands: Vec<_> = op.deref(ctx).operands().collect();
428	
429	    let (ptr, offset) = match operands.as_slice() {
430	        [ptr, offset] => (*ptr, *offset),
431	        _ => return pliron::input_err_noloc!("PtrOffset requires exactly 2 operands"),
432	    };
433	
434	    let pointee_ty_opt = operands_info
435	        .lookup_most_recent_of_type::<MirPtrType>(ctx, ptr)
436	        .map(|mir_ptr| mir_ptr.pointee);
437	
438	    let elem_ty = if let Some(pointee) = pointee_ty_opt {
439	        convert_type(ctx, pointee).map_err(anyhow_to_pliron)?
440	    } else {
441	        IntegerType::get(ctx, 8, Signedness::Signless).into()
442	    };
443	
444	    let llvm_gep = llvm::GetElementPtrOp::new(
445	        ctx,
446	        ptr,
447	        vec![llvm_export::ops::GepIndex::Value(offset)],
448	        elem_ty,
449	    );
450	    rewriter.insert_operation(ctx, llvm_gep.get_operation());
451	    rewriter.replace_operation(ctx, op, llvm_gep.get_operation());
452	
453	    Ok(())
454	}
