456	/// Convert `mir.shared_alloc` to LLVM global variable in shared address space.
457	///
458	/// GPU shared memory is represented as a global variable with address space 3.
459	/// Uses `shared_globals` to deduplicate: multiple allocations with the same
460	/// `alloc_key` share the same global.
461	///
462	/// Called directly from `MirToLlvmConversionDriver::rewrite` (not through
463	/// op_cast dispatch) because it needs the cross-function `SharedGlobalsMap`.
464	pub fn convert_shared_alloc_dc(
465	    ctx: &mut Context,
466	    rewriter: &mut DialectConversionRewriter,
467	    op: Ptr<Operation>,
468	    _operands_info: &OperandsInfo,
469	    shared_globals: &mut SharedGlobalsMap,
470	) -> Result<()> {
471	    use pliron::builtin::attributes::{IntegerAttr, TypeAttr};
472	
473	    let (alloc_key, mir_elem_type, size, alignment) = {
474	        let shared_alloc_op = dialect_mir::ops::MirSharedAllocOp::new(op);
475	        let op_ref = op.deref(ctx);
476	
477	        let alloc_key: Option<String> = shared_alloc_op
478	            .get_attr_alloc_key(ctx)
479	            .map(|s| String::from((*s).clone()));
480	
481	        let elem_type_attr = op_ref
482	            .attributes
483	            .get::<TypeAttr>(&"elem_type".try_into().unwrap())
484	            .ok_or_else(|| {
485	                anyhow_to_pliron(anyhow::anyhow!(
486	                    "MirSharedAllocOp missing elem_type TypeAttr attribute"
487	                ))
488	            })?;
489	        let mir_elem_type = elem_type_attr.get_type(ctx);
490	
491	        let size_attr = op_ref
492	            .attributes
493	            .get::<IntegerAttr>(&"size".try_into().unwrap())
494	            .ok_or_else(|| {
495	                anyhow_to_pliron(anyhow::anyhow!(
496	                    "MirSharedAllocOp missing size IntegerAttr attribute"
497	                ))
498	            })?;
499	        let size = size_attr.value().to_u64();
500	
501	        let alignment = shared_alloc_op.get_alignment_value(ctx).unwrap_or(0);
502	
503	        (alloc_key, mir_elem_type, size, alignment)
504	    };
505	
506	    // Cache hit only when the op carries a key AND that key is already in
507	    // `shared_globals`. `as_ref()` borrows for the if-let scope so the else
508	    // branch can still move `alloc_key` into `create_shared_global` (which
509	    // takes ownership and inserts it into the cache).
510	    let global_name = if let Some(key) = alloc_key.as_ref()
511	        && let Some(existing_name) = shared_globals.get(key)
512	    {
513	        existing_name.clone()
514	    } else {
515	        create_shared_global(
516	            ctx,
517	            op,
518	            shared_globals,
519	            mir_elem_type,
520	            size,
521	            alignment,
522	            alloc_key,
523	        )?
524	    };
525	
526	    let address_of_op = llvm::AddressOfOp::new(ctx, global_name, 3);
527	    rewriter.insert_operation(ctx, address_of_op.get_operation());
528	    rewriter.replace_operation(ctx, op, address_of_op.get_operation());
529	
530	    Ok(())
531	}
532	
533	/// Create a shared memory global variable in the module.
534	///
535	/// Creates an LLVM global variable with:
536	/// - Array type: `[size x element_type]`
537	/// - Address space 3 (shared memory)
538	/// - Optional alignment
539	/// - Unique generated name (`__shared_mem_N`)
540	///
541	/// The global is inserted at the front of the module block. When
542	/// `alloc_key` is `Some`, the key is moved into `shared_globals` so that
543	/// later allocations with the same key reuse this global (caller is
544	/// expected to have already checked the cache for a hit).
545	fn create_shared_global(
546	    ctx: &mut Context,
547	    op: Ptr<Operation>,
548	    shared_globals: &mut SharedGlobalsMap,
549	    mir_elem_type: TypeHandle,
550	    size: u64,
551	    alignment: u64,
552	    alloc_key: Option<String>,
553	) -> Result<pliron::identifier::Identifier> {
554	    let llvm_elem_type = convert_type(ctx, mir_elem_type).map_err(anyhow_to_pliron)?;
555	    let array_type = ArrayType::get(ctx, llvm_elem_type, size);
556	
557	    static SHARED_COUNTER: std::sync::atomic::AtomicUsize = std::sync::atomic::AtomicUsize::new(0);
558	    let counter = SHARED_COUNTER.fetch_add(1, std::sync::atomic::Ordering::SeqCst);
559	    let name: pliron::identifier::Identifier =
560	        format!("__shared_mem_{counter}").try_into().unwrap();
561	
562	    let global_op = if alignment > 0 {
563	        llvm::GlobalOp::new_with_alignment(ctx, name.clone(), array_type.into(), alignment)
564	    } else {
565	        llvm::GlobalOp::new(ctx, name.clone(), array_type.into())
566	    };
567	    global_op.set_address_space(ctx, llvm_export::types::address_space::SHARED);
568	
569	    let parent_block = op
570	        .deref(ctx)
571	        .get_parent_block()
572	        .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Op has no parent block")))?;
573	    let module_op = helpers::get_module_from_block(ctx, parent_block).map_err(anyhow_to_pliron)?;
574	    let region = module_op.deref(ctx).get_region(0);
575	    let module_block = region
576	        .deref(ctx)
577	        .iter(ctx)
578	        .next()
579	        .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Module is empty")))?;
580	
581	    global_op.get_operation().insert_at_front(module_block, ctx);
582	
583	    if let Some(key) = alloc_key {
584	        shared_globals.insert(key, name.clone());
585	    }
586	
587	    Ok(name)
588	}
