590	/// Convert `mir.global_alloc` to an LLVM global in CUDA global memory.
591	///
592	/// Ordinary Rust `static` / `static mut` values have grid scope and
593	/// application lifetime, so they live in address space 1 rather than the
594	/// per-block shared-memory address space.
595	pub fn convert_global_alloc_dc(
596	    ctx: &mut Context,
597	    rewriter: &mut DialectConversionRewriter,
598	    op: Ptr<Operation>,
599	    _operands_info: &OperandsInfo,
600	    device_globals: &mut DeviceGlobalsMap,
601	) -> Result<()> {
602	    use pliron::builtin::attributes::{StringAttr, TypeAttr};
603	
604	    let (global_key, mir_global_type, alignment, addr_space, initializer_hex) = {
605	        let global_op = dialect_mir::ops::MirGlobalAllocOp::new(op);
606	        let op_ref = op.deref(ctx);
607	
608	        let global_key_attr = op_ref
609	            .attributes
610	            .get::<StringAttr>(&"global_key".try_into().unwrap())
611	            .ok_or_else(|| {
612	                anyhow_to_pliron(anyhow::anyhow!(
613	                    "MirGlobalAllocOp missing global_key StringAttr attribute"
614	                ))
615	            })?;
616	        let global_key = String::from((*global_key_attr).clone());
617	
618	        let global_type_attr = op_ref
619	            .attributes
620	            .get::<TypeAttr>(&"global_type".try_into().unwrap())
621	            .ok_or_else(|| {
622	                anyhow_to_pliron(anyhow::anyhow!(
623	                    "MirGlobalAllocOp missing global_type TypeAttr attribute"
624	                ))
625	            })?;
626	        let mir_global_type = global_type_attr.get_type(ctx);
627	
628	        let alignment = global_op.get_alignment_value(ctx).unwrap_or(0);
629	        let initializer_hex = op_ref
630	            .attributes
631	            .get::<StringAttr>(&"global_initializer_hex".try_into().unwrap())
632	            .map(|attr| String::from((*attr).clone()));
633	
634	        // Read the address space the op's result already carries — set by
635	        // mir-importer based on the static's type (`ConstantMemory<T>` → 4,
636	        // ordinary → 1). The dialect verifier accepts both.
637	        let res_ty = op_ref.get_result(0).get_type(ctx);
638	        let addr_space = res_ty
639	            .deref(ctx)
640	            .downcast_ref::<dialect_mir::types::MirPtrType>()
641	            .map(|p| {
642	                if p.address_space == dialect_mir::types::address_space::CONSTANT {
643	                    llvm_export::types::address_space::CONSTANT
644	                } else {
645	                    llvm_export::types::address_space::GLOBAL
646	                }
647	            })
648	            .ok_or_else(|| {
649	                anyhow_to_pliron(anyhow::anyhow!(
650	                    "MirGlobalAllocOp result is not a MirPtrType"
651	                ))
652	            })?;
653	
654	        (
655	            global_key,
656	            mir_global_type,
657	            alignment,
658	            addr_space,
659	            initializer_hex,
660	        )
661	    };
662	
663	    let global_name = if let Some(existing_name) = device_globals.get(&global_key) {
664	        existing_name.clone()
665	    } else {
666	        create_device_global(
667	            ctx,
668	            op,
669	            device_globals,
670	            DeviceGlobalSpec {
671	                key: &global_key,
672	                mir_type: mir_global_type,
673	                alignment,
674	                addr_space,
675	                initializer_hex: initializer_hex.as_deref(),
676	            },
677	        )?
678	    };
679	
680	    let address_of_op = llvm::AddressOfOp::new(ctx, global_name, addr_space);
681	    rewriter.insert_operation(ctx, address_of_op.get_operation());
682	    rewriter.replace_operation(ctx, op, address_of_op.get_operation());
683	
684	    Ok(())
685	}
686	
687	struct DeviceGlobalSpec<'a> {
688	    key: &'a str,
689	    mir_type: TypeHandle,
690	    alignment: u64,
691	    addr_space: u32,
692	    initializer_hex: Option<&'a str>,
693	}
694	
695	fn create_device_global(
696	    ctx: &mut Context,
697	    op: Ptr<Operation>,
698	    device_globals: &mut DeviceGlobalsMap,
699	    spec: DeviceGlobalSpec<'_>,
700	) -> Result<pliron::identifier::Identifier> {
701	    // An explicit initializer is already the evaluated Rust allocation image.
702	    // Keep it as `[N x i8]` all the way through LLVM instead of rebuilding a
703	    // typed constant. Typed reconstruction can lose NaN payload bits and needs
704	    // a second, easily-divergent implementation of Rust struct padding.
705	    let semantic_llvm_type = convert_type(ctx, spec.mir_type).map_err(anyhow_to_pliron)?;
706	    let (llvm_global_type, alignment) = if let Some(initializer_hex) = spec.initializer_hex {
707	        let byte_count = initializer_hex_byte_count(initializer_hex).map_err(anyhow_to_pliron)?;
708	        if spec.alignment == 0 {
709	            return Err(anyhow_to_pliron(anyhow::anyhow!(
710	                "device global initializer is missing its evaluated Rust allocation alignment"
711	            )));
712	        }
713	        validate_initialized_global_layout(ctx, spec.mir_type, byte_count, spec.alignment)
714	            .map_err(anyhow_to_pliron)?;
715	        let i8_ty = IntegerType::get(ctx, 8, Signedness::Signless);
716	        (
717	            ArrayType::get(ctx, i8_ty.into(), byte_count).into(),
718	            spec.alignment,
719	        )
720	    } else {
721	        (semantic_llvm_type, spec.alignment)
722	    };
723	
724	    // Constant-memory globals reuse the Rust-side mangled name so host code can
725	    // resolve them by name via `cuModuleGetGlobal`. Ordinary device globals
726	    // are private to the kernel and get a counter-based unique name.
727	    let name: pliron::identifier::Identifier =
728	        if spec.addr_space == llvm_export::types::address_space::CONSTANT {
729	            spec.key.try_into().map_err(|e| {
730	                anyhow_to_pliron(anyhow::anyhow!(
731	                    "constant global_key {:?} is not a valid identifier: {e:?}",
732	                    spec.key
733	                ))
734	            })?
735	        } else {
736	            static DEVICE_GLOBAL_COUNTER: std::sync::atomic::AtomicUsize =
737	                std::sync::atomic::AtomicUsize::new(0);
738	            let counter = DEVICE_GLOBAL_COUNTER.fetch_add(1, std::sync::atomic::Ordering::SeqCst);
739	            format!("__device_global_{counter}").try_into().unwrap()
740	        };
741	
742	    let global_op = if alignment > 0 {
743	        llvm::GlobalOp::new_with_alignment(ctx, name.clone(), llvm_global_type, alignment)
744	    } else {
745	        llvm::GlobalOp::new(ctx, name.clone(), llvm_global_type)
746	    };
747	    global_op.set_address_space(ctx, spec.addr_space);
748	    if let Some(initializer_hex) = spec.initializer_hex {
749	        global_op.set_initializer_hex(ctx, initializer_hex);
750	    }
751	
752	    let parent_block = op
753	        .deref(ctx)
754	        .get_parent_block()
755	        .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Op has no parent block")))?;
756	    let module_op = helpers::get_module_from_block(ctx, parent_block).map_err(anyhow_to_pliron)?;
757	    let region = module_op.deref(ctx).get_region(0);
758	    let module_block = region
759	        .deref(ctx)
760	        .iter(ctx)
761	        .next()
762	        .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Module is empty")))?;
763	
764	    global_op.get_operation().insert_at_front(module_block, ctx);
765	    device_globals.insert(spec.key.to_string(), name.clone());
766	
767	    Ok(name)
768	}
769	
770	fn initializer_hex_byte_count(hex: &str) -> std::result::Result<u64, anyhow::Error> {
771	    if !hex.len().is_multiple_of(2) {
772	        anyhow::bail!("device global initializer has an odd-length hex byte string");
773	    }
774	    if let Some(invalid) = hex.bytes().find(|byte| !byte.is_ascii_hexdigit()) {
775	        anyhow::bail!(
776	            "device global initializer contains invalid hex digit {:?}",
777	            invalid as char
778	        );
779	    }
780	    u64::try_from(hex.len() / 2)
781	        .map_err(|_| anyhow::anyhow!("device global initializer is too large for LLVM"))
782	}
783	
784	/// Convert `mir.extern_shared` to LLVM extern global variable in shared address space.
785	///
786	/// Dynamic (extern) shared memory is represented as an external global variable
787	/// with address space 3 and zero-length array type `[0 x i8]`. The actual size
788	/// is determined at kernel launch via `LaunchConfig::shared_mem_bytes`.
789	///
790	/// # Per-Owner Symbols
791	///
792	/// Each function that owns an access gets a dynamic shared-memory symbol
793	/// (`__dynamic_smem_{function_name}`).
794	///
795	/// # Alignment
796	///
797	/// The alignment is pre-computed during the lowering pre-pass. It is the
798	/// maximum of the owner's body requirements and every launch-contract marker
799	/// that can reach it.
800	///
801	/// # Byte Offset
802	///
803	/// - `DynamicSharedArray::get()` / `get_raw()`: offset = 0, returns base pointer
804	/// - `DynamicSharedArray::offset(N)`: offset = N bytes, returns base + N
805	///
806	/// Called directly from `MirToLlvmConversionDriver::rewrite` (not through
807	/// op_cast dispatch) because it needs cross-function state maps.
808	pub fn convert_extern_shared_dc(
809	    ctx: &mut Context,
810	    rewriter: &mut DialectConversionRewriter,
811	    op: Ptr<Operation>,
812	    _operands_info: &OperandsInfo,
813	    shared_globals: &mut SharedGlobalsMap,
814	    dynamic_smem_alignments: &mut DynamicSmemAlignmentMap,
815	) -> Result<()> {
816	    let (byte_offset, alignment) = {
817	        let extern_shared_op = dialect_mir::ops::MirExternSharedOp::new(op);
818	        let byte_offset = extern_shared_op.get_byte_offset_value(ctx);
819	        let alignment = extern_shared_op.get_alignment_value(ctx);
820	        (byte_offset, alignment)
821	    };
822	
823	    let func_name: String = {
824	        let parent_block = op
825	            .deref(ctx)
826	            .get_parent_block()
827	            .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Op has no parent block")))?;
828	        let func_op_ptr = helpers::get_parent_func(ctx, parent_block).map_err(anyhow_to_pliron)?;
829	        let llvm_func = Operation::get_op::<llvm::FuncOp>(func_op_ptr, ctx)
830	            .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Parent op is not an llvm.func")))?;
831	        llvm_func.get_symbol_name(ctx).to_string()
832	    };
833	
834	    let global_name = get_or_create_extern_shared_global(
835	        ctx,
836	        op,
837	        &func_name,
838	        shared_globals,
839	        dynamic_smem_alignments,
840	        alignment,
841	    )?;
842	
843	    let address_of_op = llvm::AddressOfOp::new(ctx, global_name, 3);
844	    rewriter.insert_operation(ctx, address_of_op.get_operation());
845	
846	    let base_ptr = address_of_op.get_operation().deref(ctx).get_result(0);
847	
848	    if byte_offset > 0 {
849	        let i64_ty = IntegerType::get(ctx, 64, Signedness::Signless);
850	        let offset_attr = pliron::builtin::attributes::IntegerAttr::new(
851	            i64_ty,
852	            pliron::utils::apint::APInt::from_u64(
853	                byte_offset,
854	                std::num::NonZeroUsize::new(64).unwrap(),
855	            ),
856	        );
857	        let offset_const = llvm::ConstantOp::new(ctx, offset_attr.into());
858	        rewriter.insert_operation(ctx, offset_const.get_operation());
859	        let offset_value = offset_const.get_operation().deref(ctx).get_result(0);
860	
861	        let i8_ty = IntegerType::get(ctx, 8, Signedness::Signless);
862	        let gep_op = llvm::GetElementPtrOp::new(
863	            ctx,
864	            base_ptr,
865	            vec![llvm_export::ops::GepIndex::Value(offset_value)],
866	            i8_ty.into(),
867	        );
868	        rewriter.insert_operation(ctx, gep_op.get_operation());
869	        rewriter.replace_operation(ctx, op, gep_op.get_operation());
870	    } else {
871	        rewriter.replace_operation(ctx, op, address_of_op.get_operation());
872	    }
873	
874	    Ok(())
875	}
