877	/// Get or create the extern shared memory global for an owning function.
878	///
879	/// Creates an LLVM global variable with:
880	/// - Zero-length array type: `[0 x i8]`
881	/// - External linkage (no initializer)
882	/// - Address space 3 (shared memory)
883	/// - Pre-computed body and calling-kernel contract alignment
884	///
885	/// Each owning function gets its own dynamic shared memory symbol. Uses
886	/// `shared_globals` for deduplication (only one global per function).
887	fn get_or_create_extern_shared_global(
888	    ctx: &mut Context,
889	    op: Ptr<Operation>,
890	    func_name: &str,
891	    shared_globals: &mut SharedGlobalsMap,
892	    dynamic_smem_alignments: &mut DynamicSmemAlignmentMap,
893	    _requested_alignment: u64,
894	) -> Result<pliron::identifier::Identifier> {
895	    let (symbol_name, max_alignment) = dynamic_smem_alignments.get(func_name).cloned().ok_or_else(
896	        || {
897	            anyhow_to_pliron(anyhow::anyhow!(
898	                "Internal error: dynamic shared memory alignment not pre-computed for function '{}'. \
899	                 This should have been done in compute_max_dynamic_smem_alignment.",
900	                func_name
901	            ))
902	        },
903	    )?;
904	
905	    let global_created_key = format!("__dynamic_smem_global_created_{}", func_name);
906	    if shared_globals.contains_key(&global_created_key) {
907	        return Ok(symbol_name);
908	    }
909	
910	    let i8_ty = IntegerType::get(ctx, 8, Signedness::Signless);
911	    let array_type = ArrayType::get(ctx, i8_ty.into(), 0);
912	
913	    let global_op = llvm::GlobalOp::new_with_alignment(
914	        ctx,
915	        symbol_name.clone(),
916	        array_type.into(),
917	        max_alignment,
918	    );
919	    global_op.set_address_space(ctx, llvm_export::types::address_space::SHARED);
920	
921	    {
922	        use llvm_export::attributes::LinkageAttr;
923	        global_op.set_attr_llvm_global_linkage(ctx, LinkageAttr::ExternalLinkage);
924	    }
925	
926	    let parent_block = op
927	        .deref(ctx)
928	        .get_parent_block()
929	        .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Op has no parent block")))?;
930	    let module_op = helpers::get_module_from_block(ctx, parent_block).map_err(anyhow_to_pliron)?;
931	    let region = module_op.deref(ctx).get_region(0);
932	    let module_block = region
933	        .deref(ctx)
934	        .iter(ctx)
935	        .next()
936	        .ok_or_else(|| anyhow_to_pliron(anyhow::anyhow!("Module is empty")))?;
937	
938	    global_op.get_operation().insert_at_front(module_block, ctx);
939	
940	    shared_globals.insert(global_created_key, symbol_name.clone());
941	
942	    Ok(symbol_name)
943	}
