1447	    /// Build a Direct-tag `MirEnumType` the way the importer does:
1448	    /// unsigned tag of `tag_bits`, plus rustc's `total_size`/`abi_align`.
1449	    fn make_enum_ty(
1450	        ctx: &mut Context,
1451	        name: &str,
1452	        tag_bits: u32,
1453	        variants: Vec<EnumVariant>,
1454	        total_size: u64,
1455	        abi_align: u64,
1456	    ) -> TypeHandle {
1457	        let tag_ty: TypeHandle = IntegerType::get(ctx, tag_bits, Signedness::Unsigned).into();
1458	        // Sequential 0..n discriminants: these layout tests only exercise
1459	        // size/width, not value mapping.
1460	        let discriminants: Vec<u64> = (0..variants.len() as u64).collect();
1461	        MirEnumType::get_with_layout(
1462	            ctx,
1463	            name.to_string(),
1464	            tag_ty,
1465	            discriminants,
1466	            variants,
1467	            0, // tag at byte 0, like every shape these tests exercise
1468	            total_size,
1469	            abi_align,
1470	        )
1471	        .into()
1472	    }
1473	
1474	    fn unit_variants(n: usize) -> Vec<EnumVariant> {
1475	        (0..n).map(|i| EnumVariant::unit(format!("V{i}"))).collect()
1476	    }
