1478	    /// Converted enum allocation size must equal rustc's `total_size` for
1479	    /// every memory-faithful tag shape: that size is what GEP strides by.
1480	    #[test]
1481	    fn enum_conversion_strides_by_rustc_size() {
1482	        use crate::convert::types::llvm_type_size_align;
1483	
1484	        let mut ctx = make_ctx();
1485	
1486	        // #[repr(u32)] fieldless (issue #118 shape): {i32}, 4 bytes.
1487	        let repr_u32 = make_enum_ty(&mut ctx, "ReprU32", 32, unit_variants(4), 4, 4);
1488	        let conv = convert_type(&mut ctx, repr_u32).unwrap();
1489	        assert_eq!(llvm_type_size_align(&ctx, conv), (4, 4), "repr(u32) tag");
1490	
1491	        // #[repr(usize)] fieldless: {i64}, 8 bytes.
1492	        let repr_usize = make_enum_ty(&mut ctx, "ReprUsize", 64, unit_variants(4), 8, 8);
1493	        let conv = convert_type(&mut ctx, repr_usize).unwrap();
1494	        assert_eq!(llvm_type_size_align(&ctx, conv), (8, 8), "repr(usize) tag");
1495	
1496	        // u8 tag but 8-byte rustc size (repr(align(8)) raise): the converted
1497	        // struct must gain a trailing [7 x i8] pad to reach 8 bytes.
1498	        let padded = make_enum_ty(&mut ctx, "Padded", 8, unit_variants(2), 8, 8);
1499	        let conv = convert_type(&mut ctx, padded).unwrap();
1500	        let (size, _align) = llvm_type_size_align(&ctx, conv);
1501	        assert_eq!(size, 8, "trailing pad must raise the size to rustc's 8");
1502	        {
1503	            let conv_ref = conv.deref(&ctx);
1504	            let struct_ty = conv_ref
1505	                .downcast_ref::<llvm_export::types::StructType>()
1506	                .expect("converted enum is a struct");
1507	            assert_eq!(
1508	                struct_ty.fields().count(),
1509	                2,
1510	                "tag + one trailing pad field; pad appended at the END"
1511	            );
1512	        }
1513	
1514	        // u8 tag + i64 payload, rustc size 16: the slot map places the
1515	        // payload at its rustc byte offset 8 behind an explicit
1516	        // [7 x i8] filler, making the layout datalayout-independent.
1517	        let i64_payload: TypeHandle = IntegerType::get(&ctx, 64, Signedness::Unsigned).into();
1518	        let payload = make_enum_ty(
1519	            &mut ctx,
1520	            "OnePayload",
1521	            8,
1522	            vec![
1523	                EnumVariant::new_with_offsets("A".to_string(), vec![i64_payload], vec![8]),
1524	                EnumVariant::unit("B".to_string()),
1525	            ],
1526	            16,
1527	            8,
1528	        );
1529	        let conv = convert_type(&mut ctx, payload).unwrap();
1530	        let (size, _align) = llvm_type_size_align(&ctx, conv);
1531	        assert_eq!(size, 16, "natural layout matches rustc size, no pad");
1532	        let conv_ref = conv.deref(&ctx);
1533	        let struct_ty = conv_ref
1534	            .downcast_ref::<llvm_export::types::StructType>()
1535	            .expect("converted enum is a struct");
1536	        assert_eq!(
1537	            struct_ty.fields().count(),
1538	            3,
1539	            "{{tag, [7 x i8] filler, payload}}: explicit filler to byte 8"
1540	        );
1541	    }
