1761	    /// Build a `mir.shared_alloc` returning `MirPtrType<i32, addrspace=3>` of
1762	    /// length `size`, with the given alloc_key, and append it to `block`.
1763	    fn append_shared_alloc(ctx: &mut Context, block: Ptr<BasicBlock>, alloc_key: &str, size: u64) {
1764	        use pliron::builtin::attributes::IntegerAttr;
1765	        use pliron::utils::apint::APInt;
1766	
1767	        let i32_ty: TypeHandle = IntegerType::get(ctx, 32, Signedness::Signless).into();
1768	        let result_ty = MirPtrType::get_shared(ctx, i32_ty, true);
1769	        let op = Operation::new(
1770	            ctx,
1771	            mir::MirSharedAllocOp::get_concrete_op_info(),
1772	            vec![result_ty.into()],
1773	            vec![],
1774	            vec![],
1775	            0,
1776	        );
1777	        let alloc = mir::MirSharedAllocOp::new(op);
1778	        alloc.set_attr_elem_type(ctx, TypeAttr::new(i32_ty));
1779	        let size_attr = IntegerAttr::new(
1780	            IntegerType::get(ctx, 64, Signedness::Signless),
1781	            APInt::from_u64(size, std::num::NonZeroUsize::new(64).unwrap()),
1782	        );
1783	        alloc.set_attr_size(ctx, size_attr);
1784	        alloc.set_attr_alloc_key(ctx, StringAttr::new(alloc_key.to_string()));
1785	        op.insert_at_back(block, ctx);
1786	    }
