1834	    fn convert_shared_alloc_deduplicates_by_alloc_key() {
1835	        let mut ctx = make_ctx();
1836	        let (module_ptr, block) = build_kernel(&mut ctx, vec![], vec![]);
1837	        // Two allocations sharing the same alloc_key — they must collapse to
1838	        // a single underlying global (this is what enables a single `static`
1839	        // referenced from multiple sites to land in one shared region).
1840	        append_shared_alloc(&mut ctx, block, "same-key", 64);
