6	//! Atomic operation conversion: NVVM atomic dialect → LLVM atomic instructions.
7	//!
8	//! Converts NVVM atomic ops to standard LLVM atomic instructions with
9	//! proper ordering and syncscope.
10	//!
11	//! # Lowering Strategy
12	//!
13	//! Unlike most GPU intrinsics that lower to LLVM NVVM intrinsic calls or
14	//! inline PTX, atomic operations lower to **standard LLVM IR instructions**:
15	//!
16	//! | NVVM Op                 | LLVM IR                                  |
17	//! |-------------------------|------------------------------------------|
18	//! | `NvvmAtomicLoadOp`      | `load atomic ... syncscope("device")`    |
19	//! | `NvvmAtomicStoreOp`     | `store atomic ... syncscope("device")`   |
20	//! | `NvvmAtomicRmwOp`       | `atomicrmw ... syncscope("device")` `[*]`  |
21	//! | `NvvmAtomicCmpxchgOp`   | `cmpxchg ... syncscope("device")`        |
22	//!
23	//! `[*]` atomicrmw uses fence splitting workaround -- see below.
24	//!
25	//! # atomicrmw Fence Splitting Workaround
26	//!
27	//! LLVM's NVPTX backend silently drops orderings on `atomicrmw`
28	//! (fix is in LLVM 23 via PR #176015). Until then, we emit:
29	//!
30	//! ```text
31	//! Relaxed:  atomicrmw ... monotonic
32	//! Acquire:  atomicrmw ... monotonic  +  fence acquire
33	//! Release:  fence release  +  atomicrmw ... monotonic
34	//! AcqRel:   fence release  +  atomicrmw ... monotonic  +  fence acquire
35	//! SeqCst:   fence seq_cst  +  atomicrmw ... monotonic  +  fence seq_cst
36	//! ```
37	//!
38	//! All fences carry the same syncscope as the atomic op.
39	//!
40	//! # Scope → Syncscope Mapping
41	//!
42	//! | NVVM Scope | LLVM syncscope     | PTX scope |
43	//! |------------|--------------------|-----------|
44	//! | Device     | `"device"`         | `.gpu`    |
45	//! | Block      | `"block"`          | `.cta`    |
46	//! | System     | (default)          | `.sys`    |
47	
48	use crate::convert::types::convert_type;
49	
50	use dialect_nvvm::ops::atomic::{
51	    AtomicOrdering as NvvmOrdering, AtomicRmwKind as NvvmRmwKind, AtomicScope as NvvmScope,
52	    NvvmAtomicCmpxchgOp, NvvmAtomicLoadOp, NvvmAtomicOpInterface, NvvmAtomicRmwOp,
53	    NvvmAtomicStoreOp,
54	};
55	use llvm_export::attributes::{LlvmAtomicOrdering, LlvmAtomicRmwKind, LlvmSyncScope};
56	use llvm_export::ops as llvm;
57	use llvm_export::ops::{AsmKind, InlineAsmOpExt};
58	
59	use pliron::builtin::types::{IntegerType, Signedness};
60	use pliron::context::{Context, Ptr};
61	use pliron::irbuild::dialect_conversion::{DialectConversionRewriter, OperandsInfo};
62	use pliron::irbuild::inserter::Inserter;
63	use pliron::irbuild::rewriter::Rewriter;
64	use pliron::op::Op;
65	use pliron::operation::Operation;
66	use pliron::result::Result;
67	use pliron::r#type::Typed;
68	
69	// =============================================================================
70	// Scope / Ordering Mapping
71	// =============================================================================
72	
73	fn map_scope(scope: &NvvmScope) -> LlvmSyncScope {
74	    match scope {
75	        NvvmScope::Device => LlvmSyncScope::Device,
76	        NvvmScope::Block => LlvmSyncScope::Block,
77	        NvvmScope::System => LlvmSyncScope::System,
78	    }
79	}
80	
81	fn map_ordering(ord: &NvvmOrdering) -> LlvmAtomicOrdering {
82	    match ord {
83	        NvvmOrdering::Relaxed => LlvmAtomicOrdering::Monotonic,
84	        NvvmOrdering::Acquire => LlvmAtomicOrdering::Acquire,
85	        NvvmOrdering::Release => LlvmAtomicOrdering::Release,
86	        NvvmOrdering::AcqRel => LlvmAtomicOrdering::AcqRel,
87	        NvvmOrdering::SeqCst => LlvmAtomicOrdering::SeqCst,
88	    }
89	}
90	
91	fn map_rmw_kind(kind: &NvvmRmwKind) -> LlvmAtomicRmwKind {
92	    match kind {
93	        NvvmRmwKind::Add => LlvmAtomicRmwKind::Add,
94	        NvvmRmwKind::Sub => LlvmAtomicRmwKind::Sub,
95	        NvvmRmwKind::And => LlvmAtomicRmwKind::And,
96	        NvvmRmwKind::Or => LlvmAtomicRmwKind::Or,
97	        NvvmRmwKind::Xor => LlvmAtomicRmwKind::Xor,
98	        NvvmRmwKind::Xchg => LlvmAtomicRmwKind::Xchg,
99	        NvvmRmwKind::Min => LlvmAtomicRmwKind::Min,
100	        NvvmRmwKind::Max => LlvmAtomicRmwKind::Max,
101	        NvvmRmwKind::UMin => LlvmAtomicRmwKind::UMin,
102	        NvvmRmwKind::UMax => LlvmAtomicRmwKind::UMax,
103	        NvvmRmwKind::FAdd => LlvmAtomicRmwKind::FAdd,
104	    }
105	}
106	
107	// =============================================================================
108	// Helpers
109	// =============================================================================
110	
111	fn emit_fence(
112	    ctx: &mut Context,
113	    rewriter: &mut DialectConversionRewriter,
114	    ordering: LlvmAtomicOrdering,
115	    syncscope: LlvmSyncScope,
116	) {
117	    let fence = llvm::FenceOp::new(ctx, ordering, syncscope.to_pliron());
118	    rewriter.insert_operation(ctx, fence.get_operation());
119	}
120	
121	// =============================================================================
122	// Load
123	// =============================================================================
124	
125	pub(crate) fn convert_atomic_load(
126	    ctx: &mut Context,
127	    rewriter: &mut DialectConversionRewriter,
128	    op: Ptr<Operation>,
129	    _operands_info: &OperandsInfo,
130	) -> Result<()> {
131	    let nvvm_op = NvvmAtomicLoadOp::new(op);
132	    let ordering = map_ordering(&nvvm_op.ordering(ctx));
133	    let syncscope = map_scope(&nvvm_op.scope(ctx));
134	
135	    let operands: Vec<_> = op.deref(ctx).operands().collect();
136	    let ptr = operands[0];
137	    let mir_result_ty = op.deref(ctx).get_result(0).get_type(ctx);
138	    let result_ty =
139	        convert_type(ctx, mir_result_ty).map_err(|e| pliron::input_error_noloc!("{}", e))?;
140	
141	    let llvm_load = llvm::AtomicLoadOp::new(ctx, ptr, result_ty, ordering, syncscope.to_pliron());
142	    rewriter.insert_operation(ctx, llvm_load.get_operation());
143	    rewriter.replace_operation(ctx, op, llvm_load.get_operation());
144	
145	    Ok(())
146	}
147	
148	// =============================================================================
149	// Store
150	// =============================================================================
151	
152	pub(crate) fn convert_atomic_store(
153	    ctx: &mut Context,
154	    rewriter: &mut DialectConversionRewriter,
155	    op: Ptr<Operation>,
156	    _operands_info: &OperandsInfo,
157	) -> Result<()> {
158	    let nvvm_op = NvvmAtomicStoreOp::new(op);
159	    let ordering = map_ordering(&nvvm_op.ordering(ctx));
160	    let syncscope = map_scope(&nvvm_op.scope(ctx));
161	
162	    let operands: Vec<_> = op.deref(ctx).operands().collect();
163	    let val = operands[0];
164	    let ptr = operands[1];
165	
166	    let llvm_store = llvm::AtomicStoreOp::new(ctx, val, ptr, ordering, syncscope.to_pliron());
167	    rewriter.insert_operation(ctx, llvm_store.get_operation());
168	    rewriter.erase_operation(ctx, op);
169	
170	    Ok(())
171	}
172	
173	// =============================================================================
174	// Read-Modify-Write (with fence splitting workaround)
175	// =============================================================================
176	
177	pub(crate) fn convert_atomic_rmw(
178	    ctx: &mut Context,
179	    rewriter: &mut DialectConversionRewriter,
180	    op: Ptr<Operation>,
181	    _operands_info: &OperandsInfo,
182	) -> Result<()> {
183	    let nvvm_op = NvvmAtomicRmwOp::new(op);
184	    let nvvm_ordering = nvvm_op.ordering(ctx);
185	    let syncscope = map_scope(&nvvm_op.scope(ctx));
186	    let rmw_kind = map_rmw_kind(&nvvm_op.rmw_kind(ctx));
187	
188	    let operands: Vec<_> = op.deref(ctx).operands().collect();
189	    let ptr = operands[0];
190	    let val = operands[1];
191	
192	    // Fence splitting workaround for LLVM NVPTX atomicrmw ordering bug.
193	    // We emit: [optional pre-fence] + atomicrmw monotonic + [optional post-fence]
194	    // The actual atomicrmw always uses Monotonic because LLVM drops the
195	    // ordering anyway. The fences provide the correct ordering semantics.
196	
197	    // Pre-fence (if needed)
198	    match nvvm_ordering {
199	        NvvmOrdering::Release | NvvmOrdering::AcqRel => {
200	            emit_fence(ctx, rewriter, LlvmAtomicOrdering::Release, syncscope);
201	        }
202	        NvvmOrdering::SeqCst => {
203	            emit_fence(ctx, rewriter, LlvmAtomicOrdering::SeqCst, syncscope);
204	        }
205	        NvvmOrdering::Relaxed | NvvmOrdering::Acquire => {}
206	    }
207	
208	    // The atomicrmw itself -- always Monotonic
209	    let llvm_rmw = llvm::AtomicRmwOp::new(
210	        ctx,
211	        ptr,
212	        val,
213	        rmw_kind,
214	        LlvmAtomicOrdering::Monotonic,
215	        syncscope.to_pliron(),
216	    );
217	    rewriter.insert_operation(ctx, llvm_rmw.get_operation());
218	
219	    // Post-fence (if needed)
220	    match nvvm_ordering {
221	        NvvmOrdering::Acquire | NvvmOrdering::AcqRel => {
222	            emit_fence(ctx, rewriter, LlvmAtomicOrdering::Acquire, syncscope);
223	        }
224	        NvvmOrdering::SeqCst => {
225	            emit_fence(ctx, rewriter, LlvmAtomicOrdering::SeqCst, syncscope);
226	        }
227	        NvvmOrdering::Relaxed | NvvmOrdering::Release => {}
228	    }
229	
230	    rewriter.replace_operation(ctx, op, llvm_rmw.get_operation());
231	
232	    Ok(())
233	}
234	
235	// =============================================================================
236	// Compare-and-Exchange
237	// =============================================================================
238	
239	pub(crate) fn convert_atomic_cmpxchg(
240	    ctx: &mut Context,
241	    rewriter: &mut DialectConversionRewriter,
242	    op: Ptr<Operation>,
243	    _operands_info: &OperandsInfo,
244	) -> Result<()> {
245	    let nvvm_op = NvvmAtomicCmpxchgOp::new(op);
246	    let success_ord = map_ordering(&nvvm_op.success_ordering(ctx));
247	    let failure_ord = map_ordering(&nvvm_op.failure_ordering(ctx));
248	    let syncscope = map_scope(&nvvm_op.scope(ctx));
249	
250	    let operands: Vec<_> = op.deref(ctx).operands().collect();
251	    let ptr = operands[0];
252	    let cmp = operands[1];
253	    let new_val = operands[2];
254	    let llvm_cmpxchg = llvm::AtomicCmpxchgOp::new(
255	        ctx,
256	        ptr,
257	        cmp,
258	        new_val,
259	        success_ord,
260	        failure_ord,
261	        syncscope.to_pliron(),
262	    );
263	    rewriter.insert_operation(ctx, llvm_cmpxchg.get_operation());
264	
265	    // Upstream `cmpxchg` returns `{ T, i1 }`, but the NVVM op models only the
266	    // loaded value `T`. Extract element 0 and replace the NVVM op with it; this
267	    // emits the same `cmpxchg` + `extractvalue` LLVM as the pre-migration path.
268	    let cmpxchg_res = llvm_cmpxchg.get_operation().deref(ctx).get_result(0);
269	    let extract = llvm::ExtractValueOp::new(ctx, cmpxchg_res, vec![0])
270	        .map_err(|e| pliron::input_error_noloc!("{}", e))?;
271	    rewriter.insert_operation(ctx, extract.get_operation());
272	    rewriter.replace_operation(ctx, op, extract.get_operation());
273	
274	    Ok(())
275	}
276	
277	// =============================================================================
278	// Packed Atomic Add (f16x2, bf16x2) -- inline PTX
279	// =============================================================================
280	
281	/// Convert a packed atomic add op to inline PTX.
282	///
283	/// Constraints: `=r,l,r,~{memory}` -- output register, address pointer, input
284	/// register, memory clobber.
285	///
286	/// Uses `SideEffect` (not convergent): atomics are per-thread, not
287	/// warp-synchronous.
288	fn convert_packed_atom_add(
289	    ctx: &mut Context,
290	    rewriter: &mut DialectConversionRewriter,
291	    op: Ptr<Operation>,
292	    ptx_type: &str,
293	) -> Result<()> {
294	    let operands: Vec<_> = op.deref(ctx).operands().collect();
295	    if operands.len() != 2 {
296	        return pliron::input_err_noloc!(
297	            "packed atomic add requires 2 operands (address, addend), got {}",
298	            operands.len()
299	        );
300	    }
301	    let addr = operands[0];
302	    let val = operands[1];
303	
304	    let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
305	
306	    let inline_asm = llvm::InlineAsmOp::build(
307	        ctx,
308	        i32_ty.into(),
309	        vec![addr, val],
310	        &format!("atom.global.add.noftz.{ptx_type} $0, [$1], $2;"),
311	        "=r,l,r,~{memory}",
312	        AsmKind::SideEffect,
313	    );
314	
315	    let asm_op = inline_asm.get_operation();
316	    rewriter.insert_operation(ctx, asm_op);
317	    rewriter.replace_operation(ctx, op, asm_op);
318	    Ok(())
319	}
320	
321	/// Convert `nvvm.atom_add_f16x2` to inline PTX.
322	pub(crate) fn convert_atom_add_f16x2(
323	    ctx: &mut Context,
324	    rewriter: &mut DialectConversionRewriter,
325	    op: Ptr<Operation>,
326	    _operands_info: &OperandsInfo,
327	) -> Result<()> {
328	    convert_packed_atom_add(ctx, rewriter, op, "f16x2")
329	}
330	
331	/// Convert `nvvm.atom_add_bf16x2` to inline PTX.
332	pub(crate) fn convert_atom_add_bf16x2(
