        for block in region.deref(ctx).iter(ctx) {
            for op in block.deref(ctx).iter(ctx) {
                if let Some(function) = MirFuncOp::wrap(ctx, op) {
                    functions.insert(function.get_symbol_name(ctx).to_string(), op);
                }
            }
        }
